# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

import strawberry
from strawberry import federation, types
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker

# Define the GraphQL schema using Strawberry
@strawberry.federation.type
class Product:
    id: int
    name: str
    description: str
    price: float
    reviews: list[Review] = strawberry.field(resolver=lambda product, _info: [review for review in product.reviews])
    sellers: list[Seller] = strawberry.field(resolver=lambda product, _info: [seller for seller in product.sellers])
    categories: list[Category] = strawberry.field(resolver=lambda product, _info: [category for category in product.categories])
    images: list[Image] = strawberry.field(resolver=lambda product, _info: [image for image in product.images])

@strawberry.federation.type
class Review:
    id: int
    rating: float
    comment: str

@strawberry.federation.type
class Seller:
    id: int
    name: str

@strawberry.federation.type
class Category:
    id: int
    name: str

@strawberry.federation.type
class Image:
    id: int
    url: str

# Define the GraphQL query using Strawberry
@strawberry.type
class Query:
    @strawberry.field
    def product(self, id: int) -> Product:
        # Connect to the SQL database using SQLAlchemy
        engine = create_engine("sqlite:///products.db")
        Session = sessionmaker(bind=engine)
        session = Session()
        
        # Retrieve the product with the given ID from the database
        product = session.query(Product).filter_by(id=id).one()
        
        # Return the product object as a GraphQL response
        return product